'use client'

import Image from 'next/image'
import Link from 'next/link'
import { 
  Code2,
  Cpu,
  TrendingUp,
  Leaf,
  Wifi,
  ArrowLeft,
  Calendar,
  CheckSquare,
  ClipboardList,
  AlertCircle,
} from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Card } from '@/components/ui/card'
import { AuthProvider, useAuth } from '@/context/AuthContext'
import { ChatProvider } from '@/context/ChatContext'

interface Subject {
  id: string
  name: string
  icon: React.ReactNode
}

interface EventItem {
  id: string
  title: string
  date: string
  type: 'event' | 'quiz' | 'task' | 'assignment'
}

function DashboardContent() {
  const { user } = useAuth()

  const subjects: Subject[] = [
    { id: 'java', name: 'Java', icon: <Code2 className="h-5 w-5" /> },
    { id: 'os', name: 'Operating System', icon: <Cpu className="h-5 w-5" /> },
    { id: 'economics', name: 'Economics', icon: <TrendingUp className="h-5 w-5" /> },
    { id: 'environmental', name: 'Environmental Studies', icon: <Leaf className="h-5 w-5" /> },
    { id: 'iot', name: 'Internet of Things', icon: <Wifi className="h-5 w-5" /> },
  ]

  const upcomingEvents: EventItem[] = [
    { id: '1', title: 'College Annual Fest', date: 'Feb 20, 2026', type: 'event' },
    { id: '2', title: 'Guest Lecture - Cloud Computing', date: 'Feb 18, 2026', type: 'event' },
  ]

  const quizzes: EventItem[] = [
    { id: '1', title: 'Java Fundamentals Quiz', date: 'Feb 15, 2026', type: 'quiz' },
    { id: '2', title: 'OS Concepts Quiz', date: 'Feb 17, 2026', type: 'quiz' },
  ]

  const tasks: EventItem[] = [
    { id: '1', title: 'Complete Java Lab Assignment', date: 'Today', type: 'task' },
    { id: '2', title: 'Review OS Documentation', date: 'Tomorrow', type: 'task' },
  ]

  const assignments: EventItem[] = [
    { id: '1', title: 'Economics Research Paper', date: 'Feb 22, 2026', type: 'assignment' },
    { id: '2', title: 'IoT Project Report', date: 'Mar 01, 2026', type: 'assignment' },
  ]

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <header className="sticky top-0 z-40 border-b border-border bg-background/80 backdrop-blur-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link href="/chat">
                <Button variant="ghost" size="icon" title="Back to Chat">
                  <ArrowLeft className="h-5 w-5" />
                </Button>
              </Link>
              <div>
                <h1 className="text-2xl font-bold text-foreground">Dashboard</h1>
                <p className="text-sm text-muted-foreground">Welcome back, {user?.name || 'User'}!</p>
              </div>
            </div>
            <Image
              src="/kdk-logo.png"
              alt="KDK College Logo"
              width={40}
              height={40}
              className="rounded"
            />
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Subjects Section */}
        <section className="mb-12">
          <h2 className="text-xl font-semibold text-foreground mb-4">Subjects</h2>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-3">
            {subjects.map((subject) => (
              <Link key={subject.id} href={`/chat?subject=${subject.id}`}>
                <Card className="p-4 text-center hover:bg-accent hover:border-primary transition-all cursor-pointer group">
                  <div className="flex justify-center mb-3 text-primary group-hover:scale-110 transition-transform">
                    {subject.icon}
                  </div>
                  <p className="text-sm font-medium text-foreground truncate">{subject.name}</p>
                </Card>
              </Link>
            ))}
          </div>
        </section>

        {/* Upcoming Events */}
        <section className="mb-8">
          <div className="flex items-center gap-2 mb-4">
            <Calendar className="h-5 w-5 text-primary" />
            <h2 className="text-xl font-semibold text-foreground">Upcoming Events</h2>
          </div>
          {upcomingEvents.length === 0 ? (
            <Card className="p-6 text-center text-muted-foreground">
              No upcoming events
            </Card>
          ) : (
            <div className="space-y-2">
              {upcomingEvents.map((event) => (
                <Card key={event.id} className="p-4 hover:bg-accent/50 transition-colors">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="font-medium text-foreground">{event.title}</p>
                      <p className="text-sm text-muted-foreground">{event.date}</p>
                    </div>
                    <Calendar className="h-5 w-5 text-primary opacity-50" />
                  </div>
                </Card>
              ))}
            </div>
          )}
        </section>

        {/* Quizzes */}
        <section className="mb-8">
          <div className="flex items-center gap-2 mb-4">
            <CheckSquare className="h-5 w-5 text-primary" />
            <h2 className="text-xl font-semibold text-foreground">Quizzes</h2>
          </div>
          {quizzes.length === 0 ? (
            <Card className="p-6 text-center text-muted-foreground">
              No upcoming quizzes
            </Card>
          ) : (
            <div className="space-y-2">
              {quizzes.map((quiz) => (
                <Card key={quiz.id} className="p-4 hover:bg-accent/50 transition-colors">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="font-medium text-foreground">{quiz.title}</p>
                      <p className="text-sm text-muted-foreground">{quiz.date}</p>
                    </div>
                    <CheckSquare className="h-5 w-5 text-primary opacity-50" />
                  </div>
                </Card>
              ))}
            </div>
          )}
        </section>

        {/* Tasks */}
        <section className="mb-8">
          <div className="flex items-center gap-2 mb-4">
            <ClipboardList className="h-5 w-5 text-primary" />
            <h2 className="text-xl font-semibold text-foreground">Tasks</h2>
          </div>
          {tasks.length === 0 ? (
            <Card className="p-6 text-center text-muted-foreground">
              No pending tasks
            </Card>
          ) : (
            <div className="space-y-2">
              {tasks.map((task) => (
                <Card key={task.id} className="p-4 hover:bg-accent/50 transition-colors">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="font-medium text-foreground">{task.title}</p>
                      <p className="text-sm text-muted-foreground">{task.date}</p>
                    </div>
                    <ClipboardList className="h-5 w-5 text-primary opacity-50" />
                  </div>
                </Card>
              ))}
            </div>
          )}
        </section>

        {/* Upcoming Assignments */}
        <section className="mb-8">
          <div className="flex items-center gap-2 mb-4">
            <AlertCircle className="h-5 w-5 text-primary" />
            <h2 className="text-xl font-semibold text-foreground">Upcoming Assignments</h2>
          </div>
          {assignments.length === 0 ? (
            <Card className="p-6 text-center text-muted-foreground">
              No pending assignments
            </Card>
          ) : (
            <div className="space-y-2">
              {assignments.map((assignment) => (
                <Card key={assignment.id} className="p-4 hover:bg-accent/50 transition-colors">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="font-medium text-foreground">{assignment.title}</p>
                      <p className="text-sm text-muted-foreground">{assignment.date}</p>
                    </div>
                    <AlertCircle className="h-5 w-5 text-primary opacity-50" />
                  </div>
                </Card>
              ))}
            </div>
          )}
        </section>
      </main>
    </div>
  )
}

export default function DashboardPage() {
  return (
    <AuthProvider>
      <ChatProvider>
        <DashboardContent />
      </ChatProvider>
    </AuthProvider>
  )
}

